inputs.placeholder:
{
  coredns = {
    most_recent = true

    configuration_values = jsonencode({
      tolerations = [
        {
          operator = "Exists"
        }
      ]
    })
  }

  kube-proxy = {
    most_recent = true
  }

  vpc-cni = {
    most_recent = true
  }
}

{
  ingress_self_all = {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    type      = "ingress"
    self      = true
  }

  ingress_cluster_all = {
    from_port                     = 0
    to_port                       = 0
    protocol                      = "-1"
    type                          = "ingress"
    source_cluster_security_group = true
  }
}

{
  iam_role_additional_policies = {
    additional = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
  }

  ebs_optimized = true
  update_config = {
    max_unavailable_percentage = 33
  }
}
